const getBenefitsSummary = `-- name: GetBenefitsSummary :many
SELECT 'active_plans'::text AS metric, COUNT(*)::int AS metric_count, 0::numeric AS amount
FROM hrms.benefit_plans p
WHERE p.tenant_id=$1::uuid AND NOT p.inactive AND p.is_active
UNION ALL
SELECT 'open_windows', COUNT(*)::int, 0::numeric
FROM hrms.benefit_enrollment_windows w
WHERE w.tenant_id=$1::uuid AND NOT w.inactive AND w.status='open' AND w.closes_on >= CURRENT_DATE
UNION ALL
SELECT 'pending_enrollments', COUNT(*)::int, 0::numeric
FROM hrms.benefit_enrollments e
WHERE e.tenant_id=$1::uuid AND NOT e.inactive AND e.status='submitted'
UNION ALL
SELECT 'pending_claims', COUNT(*)::int, COALESCE(SUM(claim_amount), 0)::numeric
FROM hrms.benefit_claims c
WHERE c.tenant_id=$1::uuid AND NOT c.inactive AND c.status IN ('submitted','under_review')
UNION ALL
SELECT 'payable_claims', COUNT(*)::int, COALESCE(SUM(COALESCE(approved_amount, claim_amount)), 0)::numeric
FROM hrms.benefit_claims c
WHERE c.tenant_id=$1::uuid AND NOT c.inactive AND c.payment_status='pending'
UNION ALL
SELECT 'payroll_ready', COUNT(*)::int, COALESCE(SUM(COALESCE(approved_amount, claim_amount)), 0)::numeric
FROM hrms.benefit_claims c
WHERE c.tenant_id=$1::uuid AND NOT c.inactive AND c.payroll_export_status='ready'
UNION ALL
SELECT 'payroll_blocked', COUNT(*)::int, 0::numeric
FROM hrms.benefit_claims c
WHERE c.tenant_id=$1::uuid AND NOT c.inactive AND c.payroll_export_status='blocked'
`

type GetBenefitsSummaryRow struct {
	Metric      string         `db:"metric" json:"metric"`
	MetricCount int32          `db:"metric_count" json:"metric_count"`
	Amount      pgtype.Numeric `db:"amount" json:"amount"`
}

func (q *Queries) GetBenefitsSummary(ctx context.Context, summaryTenantID uuid.UUID) ([]GetBenefitsSummaryRow, error) {
	rows, err := q.db.Query(ctx, getBenefitsSummary, summaryTenantID)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var items []GetBenefitsSummaryRow
	for rows.Next() {
		var i GetBenefitsSummaryRow
		if err := rows.Scan(&i.Metric, &i.MetricCount, &i.Amount); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

